// // This module implements a 1-to-4 demultiplexer with 2-bit select input.
module multiplexer(
    input [3:0] in,
    input [1:0] sel,
    output reg out
);

    always @(*) begin
        case (sel)
            2'b00: out = in[0];
            2'b01: out = in[1];
            2'b10: out = in[2];
            2'b11: out = in[3];
            default: out = 1'b0;
        endcase
    end

endmodule
